import { useContext } from 'react';

import { MapStore } from './map-store.context.js';
import type {
  MapOverlayState,
  MapSelectionState,
  ZoomState,
} from '../types/state.js';

export const useSetState = () => {
  const { setState } = useContext(MapStore);

  return setState;
};

export * from './selectors.js';

export const useSetStateSelection = () => {
  const setState = useSetState();

  return (newSelectionState: Partial<MapSelectionState>) => {
    setState((prev) => ({
      ...prev,
      selection: {
        ...prev.selection,
        ...newSelectionState,
      },
    }));
  };
};

